//! Implementation of [`TaskManager`]
//!
//!
//!
//! It is only used to manage processes and schedule process based on ready queue.
//! Other CPU process monitoring functions are in Processor.

use super::{ProcessControlBlock, TaskControlBlock, TaskStatus};
use crate::sync::UPSafeCell;
use alloc::collections::{BTreeMap, VecDeque};
use alloc::sync::Arc;
use alloc::vec::Vec;
use lazy_static::*;
use spin::{Lazy, Mutex};
///A array of `TaskControlBlock` that is thread-safe
pub struct TaskManager {
    ready_queue: VecDeque<Arc<TaskControlBlock>>,
    ///block map : <pid,>
    block_map: BTreeMap<usize, Arc<TaskControlBlock>>,
    /// The stopping task, leave a reference so that the kernel stack will not be recycled when switching tasks
    stop_task: Option<Arc<TaskControlBlock>>,
}

/// A simple FIFO scheduler.
impl TaskManager {
    ///Creat an empty TaskManager
    pub fn new() -> Self {
        Self {
            ready_queue: VecDeque::new(),
            block_map: BTreeMap::new(),
            stop_task: None,
        }
    }
    /// Add process back to ready queue
    pub fn add(&mut self, task: Arc<TaskControlBlock>) {
        self.ready_queue.push_back(task);
    }
    /// Add a task to stopping task
    pub fn add_stop(&mut self, task: Arc<TaskControlBlock>) {
        // NOTE: as the last stopping task has completely stopped (not
        // using kernel stack any more, at least in the single-core
        // case) so that we can simply replace it;
        self.stop_task = Some(task);
    }
    /// Add a task to block task
    pub fn add_block(&mut self, task: Arc<TaskControlBlock>) {
        //The blocking queue
        // which temporarily holds tasks waiting for timer expiration.
        let process = task.process.upgrade().unwrap();
        self.block_map.insert(process.getpid(), task);
    }

    /// Take a process out of the ready queue
    pub fn fetch(&mut self) -> Option<Arc<TaskControlBlock>> {
        debug!("ready queue size:{}", self.ready_queue.len());
        self.ready_queue.pop_front()
    }
    pub fn remove(&mut self, task: Arc<TaskControlBlock>) {
        if let Some((id, _)) = self
            .ready_queue
            .iter()
            .enumerate()
            .find(|(_, t)| Arc::as_ptr(t) == Arc::as_ptr(&task))
        {
            self.ready_queue.remove(id);
        }
    }
    /// remove block
    pub fn remove_block(&mut self, task: &Arc<TaskControlBlock>) {
        let process = task.process.upgrade().unwrap();
        let pid = process.getpid();
        //debug!("remove block :{}",pid);
        self.block_map.remove(&pid);
    }
    /// remove block by pid
    pub fn remove_block_by_pid(&mut self, pid: usize) {
        //debug!("remove block by pid:{}",pid);
        if let Some(task) = self.block_map.remove(&pid) {
            let mut inner = task.inner_exclusive_access();
            if inner.task_status != TaskStatus::Ready {
                inner.task_status = TaskStatus::Ready;
                drop(inner);
                self.add(task);
                debug!("(remove_block_by_pid) Add task ok : {}", pid);
            }
        }
    }
}

lazy_static! {
    /// TASK_MANAGER instance through lazy_static!
    pub static ref TASK_MANAGER: UPSafeCell<TaskManager> =
        unsafe { UPSafeCell::new(TaskManager::new()) };
    /// PID2PCB instance (map of pid to pcb)
    pub static ref PID2PCB: UPSafeCell<BTreeMap<usize, Arc<ProcessControlBlock>>> =
        unsafe { UPSafeCell::new(BTreeMap::new()) };

    pub static ref TID2TCB: UPSafeCell<BTreeMap<usize,Arc<TaskControlBlock>>> =
        unsafe { UPSafeCell::new(BTreeMap::new())};
}

/// Add a task to ready queue
pub fn add_task(task: Arc<TaskControlBlock>) {
    //debug!("kernel: TaskManager::add_task");
    TASK_MANAGER.exclusive_access().add(task);
}
/// Add a task to block queue
pub fn add_block_task(task: Arc<TaskControlBlock>) {
    TASK_MANAGER.exclusive_access().add_block(task);
}

/// Wake up a task
pub fn wakeup_task(task: Arc<TaskControlBlock>) {
    //trace!("kernel: TaskManager::wakeup_task");
    let mut task_inner = task.inner_exclusive_access();
    task_inner.task_status = TaskStatus::Ready;
    drop(task_inner);
    TASK_MANAGER.exclusive_access().remove_block(&task);
    add_task(task);
}
pub fn wakeup_futex_task(task: Arc<TaskControlBlock>) {
    debug!("in wake up futex task");
    let mut task_inner = task.inner_exclusive_access();
    task_inner.task_status = TaskStatus::Ready;
    drop(task_inner);
    TASK_MANAGER.exclusive_access().remove_block(&task);
    add_task(task);
}

/// wake up a task by pid
pub fn wakeup_task_by_pid(pid: usize) {
    //debug!("block task id:{}",pid);
    TASK_MANAGER.exclusive_access().remove_block_by_pid(pid);
    //debug!("wake up task {} ok",pid);
}

/// Remove a task from the ready queue
pub fn remove_task(task: Arc<TaskControlBlock>) {
    //trace!("kernel: TaskManager::remove_task");
    TASK_MANAGER.exclusive_access().remove(task);
}

/// Set a task to stop-wait status, waiting for its kernel stack out of use.
pub fn add_stopping_task(task: Arc<TaskControlBlock>) {
    TASK_MANAGER.exclusive_access().add_stop(task);
}

/// Get process by pid
pub fn pid2process(pid: usize) -> Option<Arc<ProcessControlBlock>> {
    info!("(pid2process) pid: {}", pid);
    let map = PID2PCB.exclusive_access();
    map.get(&pid).map(Arc::clone)
}

/// Get process by pid
pub fn tid2task(tid: usize) -> Option<Arc<TaskControlBlock>> {
    info!("(tid2task) tid: {}", tid);
    let map = TID2TCB.exclusive_access();
    map.get(&tid).map(Arc::clone)
}

/// Insert item(pid, pcb) into PID2PCB map (called by do_fork AND ProcessControlBlock::new)
pub fn insert_into_pid2process(pid: usize, process: Arc<ProcessControlBlock>) {
    info!("(insert_into_pid2process) pid: {}", pid);
    PID2PCB.exclusive_access().insert(pid, process);
}

pub fn insert_into_tid2task(tid: usize, task: Arc<TaskControlBlock>) {
    info!("(insert_into_tid2task) pid: {}", tid);
    TID2TCB.exclusive_access().insert(tid, task);
}

/// Remove item(pid, _some_pcb) from PDI2PCB map (called by exit_current_and_run_next)
pub fn remove_from_pid2process(pid: usize) {
    info!("(remove_from_pid2process) pid: {}", pid);
    PID2PCB.exclusive_access().remove(&pid);
}

pub fn remove_from_tid2task(tid: usize) {
    info!("(remove_from_tid2task) pid: {}", tid);
    TID2TCB.exclusive_access().remove(&tid);
}
/// Take a process out of the ready queue
pub fn fetch_task() -> Option<Arc<TaskControlBlock>> {
    debug!("kernel: TaskManager::fetch_task");
    TASK_MANAGER.exclusive_access().fetch()
}

// process num
pub fn process_num() -> usize {
    PID2PCB.exclusive_access().len()
}

/// 线程组
pub static THREAD_GROUP: Lazy<Mutex<BTreeMap<usize, Vec<Arc<ProcessControlBlock>>>>> =
    Lazy::new(|| Mutex::new(BTreeMap::new()));

pub fn insert_into_thread_group(pid: usize, process: &Arc<ProcessControlBlock>) {
    THREAD_GROUP
        .lock()
        .entry(pid)
        .or_insert_with(Vec::new)
        .push(process.clone());
}
/// 删除整个线程组,同时将线程从pid2process移除
pub fn remove_all_from_thread_group(pid: usize) {
    THREAD_GROUP.lock().remove(&pid);
}

//! Implementation of [`Processor`] and Intersection of control flow
//!
//!
//!
//! Here, the continuous operation of user apps in CPU is maintained,
//! the current running state of CPU is recorded,
//! and the replacement and transfer of control flow of different applications are executed.

use super::__switch;
use super::{fetch_task, TaskStatus};
use super::{ProcessControlBlock, TaskContext, TaskControlBlock};
use crate::config::PAGE_SIZE_BITS;
use crate::hal::trap::TrapContext;
use crate::mm::MapPermission;
use crate::sync::UPSafeCell;
use crate::syscall::MmapFlags;
use crate::timer::check_timer;
use alloc::sync::Arc;
use core::arch::asm;
//use core::str::next_code_point;
use lazy_static::*;
#[cfg(target_arch = "loongarch64")]
use loongarch64::register::{asid, pgdh, pgdl};

/// Processor management structure
pub struct Processor {
    /// The task currently executing on the current processor
    pub current: Option<Arc<TaskControlBlock>>,

    ///The basic control flow of each core, helping to select and switch process
    idle_task_cx: TaskContext,
}

impl Processor {
    pub fn new() -> Self {
        Self {
            current: None,
            idle_task_cx: TaskContext::zero_init(),
        }
    }

    ///Get mutable reference to `idle_task_cx`
    fn get_idle_task_cx_ptr(&mut self) -> *mut TaskContext {
        // info!(
        //     "get_idle_task_cx_ptr: idle task cx ptr: {:p}",
        //     &self.idle_task_cx
        // );
        &mut self.idle_task_cx as *mut _
    }

    ///Get current task in moving semanteme
    pub fn take_current(&mut self) -> Option<Arc<TaskControlBlock>> {
        self.current.take()
    }

    ///Get current task in cloning semanteme
    pub fn current(&self) -> Option<Arc<TaskControlBlock>> {
        self.current.as_ref().map(Arc::clone)
    }
}

lazy_static! {
    pub static ref PROCESSOR: UPSafeCell<Processor> = unsafe { UPSafeCell::new(Processor::new()) };
}

///The main part of process execution and scheduling
///Loop `fetch_task` to get the process that needs to run, and switch the process through `__switch`
pub fn run_tasks() {
    loop {
        let mut processor = PROCESSOR.exclusive_access();

        if let Some(task) = fetch_task() {
            debug!("in processor run task, fetch task ok");
            //check_timer();
            let idle_task_cx_ptr = processor.get_idle_task_cx_ptr();
            // access coming task TCB exclusively
            task.process
                .upgrade()
                .unwrap()
                .inner_exclusive_access()
                .tms
                .set_begin();
            let mut task_inner = task.inner_exclusive_access();
            let next_task_cx_ptr = &task_inner.task_cx as *const TaskContext;
            task_inner.task_status = TaskStatus::Running;
            // release coming task_inner manually
            drop(task_inner);
            // release coming task TCB manually
            processor.current = Some(task);
            // release processor manually
            drop(processor);
            info!(
                "idle task cx ptr: {:p}, next task cx ptr: {:p}",
                idle_task_cx_ptr, next_task_cx_ptr
            );
            warn!(
                "idle_task_cx_ptr ra: {:#x}, next_task_cx_ptr ra: {:#x}",
                unsafe { (*idle_task_cx_ptr).get_ra() },
                unsafe { (*next_task_cx_ptr).get_ra() }
            );
            warn!(
                "idle_task_cx_ptr sp: {:#x}, next_task_cx_ptr sp: {:#x}",
                unsafe { (*idle_task_cx_ptr).get_sp() },
                unsafe { (*next_task_cx_ptr).get_sp() }
            );
            #[cfg(target_arch = "loongarch64")]
            {
                let (tlbrsave, sp) = read_tlbrsave_and_sp();
                warn!("tlbrsave: {:#x}, sp: {:#x}", tlbrsave, sp);
            }
            unsafe {
                __switch(idle_task_cx_ptr, next_task_cx_ptr);
            }
        } else {
            //debug!(" no available in run_tasks,to check timer");
            check_timer();
        }
    }
}

/// Get current task through take, leaving a None in its place
pub fn take_current_task() -> Option<Arc<TaskControlBlock>> {
    PROCESSOR.exclusive_access().take_current()
}

/// Get a copy of the current task
pub fn current_task() -> Option<Arc<TaskControlBlock>> {
    PROCESSOR.exclusive_access().current()
}

/// get current process
pub fn current_process() -> Arc<ProcessControlBlock> {
    current_task().unwrap().process.upgrade().unwrap()
}

/// Get the current user token(addr of page table)
pub fn current_user_token() -> usize {
    let task = current_task().unwrap();
    task.get_user_token()
}

/// Get the mutable reference to trap context of current task
pub fn current_trap_cx() -> &'static mut TrapContext {
    current_task()
        .unwrap()
        .inner_exclusive_access()
        .get_trap_cx()
}

/// get the user virtual address of trap context
pub fn current_trap_cx_user_va() -> usize {
    debug!("current task tid is : {}", current_task().unwrap().tid());
    current_task().unwrap().trap_cx_user_va()
}

pub fn current_trap_cx_user_pa() -> usize {
    current_task().unwrap().trap_cx_user_pa()
}

/// get the top addr of kernel stack
pub fn current_kstack_top() -> usize {
    current_task().unwrap().kstack.get_top()
}

/// Return to idle control flow for new scheduling
pub fn schedule(switched_task_cx_ptr: *mut TaskContext) {
    let mut processor = PROCESSOR.exclusive_access();
    let idle_task_cx_ptr = processor.get_idle_task_cx_ptr();
    drop(processor);
    //debug!("in schedule, to switch, currrent ra is : {},current sp is :{}, next ra is :{}, next sp is : {}",unsafe{(*switched_task_cx_ptr).get_ra()},unsafe{(*switched_task_cx_ptr).get_sp()},unsafe{(*idle_task_cx_ptr).get_ra()},unsafe{(*idle_task_cx_ptr).get_sp()});
    unsafe {
        __switch(switched_task_cx_ptr, idle_task_cx_ptr);
    }
}

/// Create a MapArea for the current task
pub fn mmap(
    addr: usize,
    len: usize,
    port: MapPermission,
    flags: MmapFlags,
    fd: Option<Arc<crate::fs::OSInode>>,
    off: usize,
) -> usize {
    current_process()
        .inner_exclusive_access()
        .memory_set
        .mmap(addr, len, port, flags, fd, off)
}

/// Unmap the MapArea for the current task
pub fn munmap(addr: usize, len: usize) -> isize {
    current_task()
        .unwrap()
        .process
        .upgrade()
        .unwrap()
        .inner_exclusive_access()
        .memory_set
        .munmap(addr, len)
}

#[cfg(target_arch = "loongarch64")]
fn read_tlbrsave_and_sp() -> (usize, usize) {
    let tlbrsave: usize;
    let sp: usize;
    unsafe {
        asm!(
            "csrrd {}, 0x30",
            "move {}, $sp",
            out(reg) tlbrsave,
            out(reg) sp
        );
    }
    (tlbrsave, sp)
}

