    pub fn send(&self, buf: &[u8]) -> AxResult<usize> {
        match self {
            Socket::Udp(udpsocket) => Ok(udpsocket.lock().send(buf)?),
            Socket::Tcp(tcpsocket) => Ok(tcpsocket.lock().send(buf)?),
        }
    }

    fn recv(&self, buf: &mut [u8]) -> AxResult<usize> {
        match self {
            Socket::Udp(udpsocket) => Ok(udpsocket.lock().recv_from(buf).map(|e| e.0)?),
            Socket::Tcp(tcpsocket) => Ok(tcpsocket.lock().recv(buf)?),
        }
    }

    pub fn poll(&self) -> AxResult<PollState> {
        match self {
            Socket::Udp(udpsocket) => Ok(udpsocket.lock().poll()?),
            Socket::Tcp(tcpsocket) => Ok(tcpsocket.lock().poll()?),
        }
    }

    fn local_addr(&self) -> AxResult<SocketAddr> {
        match self {
            Socket::Udp(udpsocket) => Ok(udpsocket.lock().local_addr()?),
            Socket::Tcp(tcpsocket) => Ok(tcpsocket.lock().local_addr()?),
        }
    }

    fn peer_addr(&self) -> AxResult<SocketAddr> {
        match self {
            Socket::Udp(udpsocket) => Ok(udpsocket.lock().peer_addr()?),
            Socket::Tcp(tcpsocket) => Ok(tcpsocket.lock().peer_addr()?),
        }
    }

    fn bind(&self, addr: SocketAddr) -> AxResult<()> {
        match self {
            Socket::Udp(udpsocket) => Ok(udpsocket.lock().bind(addr)?),
            Socket::Tcp(tcpsocket) => Ok(tcpsocket.lock().bind(addr)?),
        }
    }

    fn connect(&self, addr: SocketAddr) -> AxResult {
        match self {
            Socket::Udp(udpsocket) => Ok(udpsocket.lock().connect(addr)?),
            Socket::Tcp(tcpsocket) => Ok(tcpsocket.lock().connect(addr)?),
        }
    }

    pub fn sendto(&self, buf: &[u8], addr: SocketAddr) -> SyscallRet {
        match self {
            // diff: must bind before sendto
            Socket::Udp(udpsocket) => Ok(udpsocket.lock().send_to(buf, addr)?),
            Socket::Tcp(_) => Err(SysErrNo::EISCONN.into()),
        }
    }

    fn recvfrom(&self, buf: &mut [u8]) -> AxResult<(usize, Option<SocketAddr>)> {
        match self {
            // diff: must bind before recvfrom
            Socket::Udp(udpsocket) => Ok(udpsocket
                .lock()
                .recv_from(buf)
                .map(|res| (res.0, Some(res.1)))?),
            Socket::Tcp(tcpsocket) => Ok(tcpsocket.lock().recv(buf).map(|res| (res, None))?),
        }
    }

    fn listen(&self) -> AxResult {
        match self {
            Socket::Udp(_) => Err(SysErrNo::EOPNOTSUPP.into()),
            Socket::Tcp(tcpsocket) => Ok(tcpsocket.lock().listen()?),
        }

use alloc::{collections::btree_map::BTreeMap, sync::Arc, vec::Vec};
use spin::{Lazy, Mutex};

use super::{FrameTracker, VirtPageNum};
pub const GROUP_SIZE: usize = 0x1000;

//共享空间管理器,mmap专用，因为只有mmap会在有固定内容但没加载时fork
pub static GROUP_SHARE: Lazy<Mutex<GroupManager>> = Lazy::new(|| Mutex::new(GroupManager::new()));
//以MapArea为单元分组，每个MapArea一个groupid,在同一个group内的MapArea共享内存
struct GroupInner {
    //该组内共享的帧
    pub shared_frames: BTreeMap<VirtPageNum, Arc<FrameTracker>>,
    //该组内剩余的maparea数量
    pub maparea_num: usize,
}
impl GroupInner {
    pub fn new() -> GroupInner {
        Self {
            shared_frames: BTreeMap::new(),
            maparea_num: 0,
        }
    }
}
pub struct GroupManager {
    unused_id: Vec<usize>,
    groups: BTreeMap<usize, GroupInner>,
}
impl GroupManager {
    pub fn new() -> GroupManager {
        Self {
            unused_id: (1..GROUP_SIZE).collect(),
            groups: BTreeMap::new(),
        }
    }
    //分配一个groupID
    pub fn alloc_id(&mut self) -> usize {
        if let Some(id) = self.unused_id.pop() {
            id
        } else {
            0
        }
    }
    //添加一个maparea
    pub fn add_area(&mut self, id: usize) {
        if id == 0 {
            return;
        }
        //println!("add area {}", id);
        if !self.groups.contains_key(&id) {
            self.groups.insert(id, GroupInner::new());
        }
        self.groups.get_mut(&id).unwrap().maparea_num += 1;
    }
    //释放一个maparea
    pub fn del_area(&mut self, id: usize) {
        if id == 0 {
            return;
        }
        //println!("del area {}", id);
        let num = self.groups.get_mut(&id).unwrap();
        num.maparea_num -= 1;
        if num.maparea_num == 0 {
            self.groups.remove(&id);
            self.unused_id.push(id);
        }
    }
    //添加共享帧
    //同一组只有第一次触发懒分配时调用，所有权直接转移给shared_frames
    pub fn add_frame(&mut self, id: usize, vpn: VirtPageNum, frame: Arc<FrameTracker>) {
        self.groups
            .get_mut(&id)
            .unwrap()
            .shared_frames
            .insert(vpn, frame);
    }
    //查找共享帧
    pub fn find(&mut self, id: usize, vpn: VirtPageNum) -> Option<Arc<FrameTracker>> {
        if id == 0 {
            return None;
        }
        //get(&id)必定成功
        if let Some(frame) = self.groups.get(&id).unwrap().shared_frames.get(&vpn) {
            Some(frame.clone())
        } else {
            None
        }
    }
}

use core::array::from_fn;

use alloc::sync::Arc;

use crate::sync::UPSafeCell;

use super::{KSigAction, SIG_MAX_NUM};

pub struct SigTable {
    pub inner: UPSafeCell<SigTableInner>,
}

impl SigTable {
    pub fn new() -> Self {
        unsafe {
            Self {
                inner: UPSafeCell::new(SigTableInner::new()),
            }
        }
    }
    pub fn from_another(another: &Arc<SigTable>) -> Self {
        unsafe {
            Self {
                inner: UPSafeCell::new(SigTableInner::from_another(another.get_ref())),
            }
        }
    }
    pub fn get_ref(&self) -> &SigTableInner {
        self.inner.get_unchecked_ref()
    }
    pub fn get_mut(&self) -> &mut SigTableInner {
        self.inner.get_unchecked_mut()
    }

    pub fn action(&self, signo: usize) -> KSigAction {
        self.get_ref().actions[signo]
    }
    pub fn set_action(&self, signo: usize, act: KSigAction) {
        self.get_mut().actions[signo] = act
    }
    pub fn exit_code(&self) -> i32 {
        self.get_ref().group_exit_code.unwrap()
    }
    pub fn is_exited(&self) -> bool {
        self.get_ref().group_exit_code.is_some()
    }
    pub fn not_exited(&self) -> bool {
        self.get_ref().group_exit_code.is_none()
    }
    pub fn set_exit_code(&self, exit_code: i32) {
        self.get_mut().group_exit_code = Some(exit_code)
    }
}

pub struct SigTableInner {
    actions: [KSigAction; SIG_MAX_NUM + 1],
    group_exit_code: Option<i32>,
}

impl SigTableInner {
    pub fn new() -> Self {
        Self {
            actions: from_fn(|signo| KSigAction::new(signo, false)),
            group_exit_code: None,
        }
    }
    pub fn from_another(other: &SigTableInner) -> Self {
        Self {
            actions: other.actions.clone(),
            group_exit_code: None,
        }
    }
}
